using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.AspNetCore.Authorization;
using FeedAggregator.Models;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

// Policy setup: Add "FeedAggregatorPolicy" policy in your authorization configuration.

namespace FeedAggregator.Controllers
{
    [ApiController]
    [Route("[controller]")]
    [Authorize(Policy = "FeedAggregatorPolicy")]
    public class FeedAggregatorController : ControllerBase
    {
        private readonly IFeedReader _feedReader;
        private readonly ILogger<FeedAggregatorController> _logger;

        public FeedAggregatorController(IFeedReader feedReader, ILogger<FeedAggregatorController> logger)
        {
            _feedReader = feedReader;
            _logger = logger;
        }

        [HttpPost]
        [Authorize(Policy = "FeedAggregatorPolicy")]
        public async Task<IActionResult> PostAsync([FromBody] FeedAggregatorRequestDto request)
        {
            if (request == null || request.SourceUrls == null || !request.SourceUrls.Any())
            {
                return BadRequest(new { error = "Invalid source URLs" });
            }

            var feedEntries = new List<Entry>();
            foreach (var sourceUrl in request.SourceUrls)
            {
                Feed feed;
                try
                {
                    feed = await _feedReader.ReadFeedAsync(sourceUrl);
                }
                catch (FeedAggregatorValidationException ex)
                {
                    _logger.LogWarning("Feed validation failed for URL {SourceUrl}: {Message}", sourceUrl, ex.Message);
                    return BadRequest(new { error = $"Invalid feed URL: {sourceUrl}" });
                }
                catch (FeedAggregatorAccessDeniedException)
                {
                    _logger.LogWarning("Access denied for feed URL {SourceUrl}", sourceUrl);
                    return NotFound();
                }
                catch (FeedAggregatorException ex)
                {
                    _logger.LogError(ex, "Feed reading failed for URL {SourceUrl}", sourceUrl);
                    return StatusCode(500, new { error = "Internal server error" });
                }

                if (feed == null)
                {
                    _logger.LogWarning("Feed not found or unreadable for URL {SourceUrl}", sourceUrl);
                    return BadRequest(new { error = $"Failed to read feed from {sourceUrl}" });
                }

                feedEntries.AddRange(feed.Entries);
            }

            var mergedFeed = new Feed
            {
                Title = "Merged Feed",
                Description = "Aggregated feed from multiple sources",
                Entries = feedEntries
            };

            return Ok(mergedFeed);
        }
    }
}
