// Models/FeedReader.cs
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Threading.Tasks;
using System.Xml.Linq;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Configuration;
using System.Net;
using System.Text.RegularExpressions;

namespace FeedAggregator.Models
{
    public class FeedReader : IFeedReader
    {
        private static readonly HashSet<string> AllowedDomains = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "feeds.bbci.co.uk",
            "rss.nytimes.com",
            "www.reddit.com"
            // Add more allowed domains as needed
        };

        private static readonly HashSet<string> AllowedSchemes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "https"
        };

        private readonly HttpClient _httpClient;
        private readonly ILogger<FeedReader> _logger;
        private readonly IConfiguration _configuration;

        public FeedReader(HttpClient httpClient, ILogger<FeedReader> logger, IConfiguration configuration)
        {
            _httpClient = httpClient;
            _logger = logger;
            _configuration = configuration;
        }

        public async Task<Feed> ReadFeedAsync(string sourceUrl)
        {
            Uri uri = ValidateAndCanonicalizeUrl(sourceUrl);

            var host = uri.Host;
            if (!AllowedDomains.Contains(host))
            {
                throw new FeedAggregatorValidationException("Domain is not allowed.");
            }

            if (!AllowedSchemes.Contains(uri.Scheme))
            {
                throw new FeedAggregatorValidationException("Scheme is not allowed.");
            }

            IPAddress[] addresses;
            try
            {
                addresses = await Dns.GetHostAddressesAsync(host);
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "DNS resolution failed for {Host}", host);
                throw new FeedAggregatorAccessDeniedException();
            }

            foreach (var ip in addresses)
            {
                if (IsNonPublicIp(ip))
                {
                    throw new FeedAggregatorAccessDeniedException();
                }
            }

            var request = new HttpRequestMessage(HttpMethod.Get, uri)
            {
                Version = new Version(2, 0)
            };

            request.Headers.UserAgent.ParseAdd("FeedAggregator/1.0");

            HttpResponseMessage response;
            try
            {
                response = await _httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "HTTP request failed for {Uri}", uri);
                throw new FeedAggregatorException("HTTP request failed.");
            }

            if (!response.IsSuccessStatusCode)
            {
                throw new FeedAggregatorException("Feed source returned error.");
            }

            var contentType = response.Content.Headers.ContentType?.MediaType?.ToLowerInvariant();
            if (contentType != null && !contentType.Contains("xml") && !contentType.Contains("rss") && !contentType.Contains("atom"))
            {
                throw new FeedAggregatorValidationException("Content type not allowed.");
            }

            var content = await response.Content.ReadAsStringAsync();
            XDocument document;
            try
            {
                document = XDocument.Parse(content, LoadOptions.None);
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Feed XML parsing failed");
                throw new FeedAggregatorValidationException("Invalid feed format.");
            }

            var feed = ParseFeed(document);
            return feed;
        }

        private static Uri ValidateAndCanonicalizeUrl(string rawUrl)
        {
            if (string.IsNullOrWhiteSpace(rawUrl))
            {
                throw new FeedAggregatorValidationException("URL is empty.");
            }

            if (!Uri.TryCreate(rawUrl, UriKind.Absolute, out var uri))
            {
                throw new FeedAggregatorValidationException("URL is not absolute.");
            }

            if (uri.Scheme != Uri.UriSchemeHttps)
            {
                throw new FeedAggregatorValidationException("Only HTTPS is allowed.");
            }

            if (uri.HostNameType != UriHostNameType.Dns)
            {
                throw new FeedAggregatorValidationException("Host must be DNS.");
            }

            var host = uri.Host;
            if (!Regex.IsMatch(host, @"^[a-zA-Z0-9\.-]+$"))
            {
                throw new FeedAggregatorValidationException("Host contains invalid characters.");
            }

            return uri;
        }

        private static bool IsNonPublicIp(IPAddress ip)
        {
            if (IPAddress.IsLoopback(ip))
            {
                return true;
            }

            if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetwork)
            {
                var bytes = ip.GetAddressBytes();
                // 10.0.0.0/8
                if (bytes[0] == 10)
                {
                    return true;
                }
                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                {
                    return true;
                }
                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                {
                    return true;
                }
                // 127.0.0.0/8
                if (bytes[0] == 127)
                {
                    return true;
                }
                // 169.254.0.0/16 (link-local)
                if (bytes[0] == 169 && bytes[1] == 254)
                {
                    return true;
                }
            }
            else if (ip.AddressFamily == System.Net.Sockets.AddressFamily.InterNetworkV6)
            {
                if (ip.IsIPv6LinkLocal || ip.IsIPv6Multicast || ip.IsIPv6SiteLocal || ip.IsIPv6Teredo || ip.IsIPv6UniqueLocal)
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6Loopback))
                {
                    return true;
                }
                if (ip.Equals(IPAddress.IPv6None))
                {
                    return true;
                }
            }
            return false;
        }

        private static Feed ParseFeed(XDocument document)
        {
            var root = document.Root;
            if (root == null)
            {
                throw new FeedAggregatorValidationException("Feed XML is empty.");
            }

            string title = root.Element("title")?.Value ?? "Untitled Feed";
            string description = root.Element("description")?.Value ?? string.Empty;

            var entries = root.Elements("entry").Select(ParseEntry).ToList();

            return new Feed
            {
                Title = title,
                Description = description,
                Entries = entries
            };
        }

        private static Entry ParseEntry(XElement entry)
        {
            if (entry == null)
            {
                throw new FeedAggregatorValidationException("Entry is null.");
            }

            var id = entry.Element("id")?.Value ?? Guid.NewGuid().ToString();
            var title = entry.Element("title")?.Value ?? string.Empty;
            var content = entry.Element("content")?.Value ?? string.Empty;
            var publishedStr = entry.Element("published")?.Value;
            var updatedStr = entry.Element("updated")?.Value;

            DateTime published = DateTime.UtcNow;
            DateTime updated = DateTime.UtcNow;
            if (!string.IsNullOrEmpty(publishedStr))
            {
                DateTime.TryParse(publishedStr, out published);
            }
            if (!string.IsNullOrEmpty(updatedStr))
            {
                DateTime.TryParse(updatedStr, out updated);
            }

            return new Entry
            {
                Id = id,
                Title = title,
                Content = content,
                Published = published,
                Updated = updated
            };
        }
    }
}
