using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using System.Xml.Linq;
using System.Net.Http;

namespace FeedAggregator.Models
{
    public interface IFeedReader
    {
        Task<Feed> ReadFeedAsync(string sourceUrl);
    }

    public class FeedReader : IFeedReader
    {
        private readonly HttpClient _httpClient;

        public FeedReader(HttpClient httpClient)
        {
            _httpClient = httpClient;
        }

        public async Task<Feed> ReadFeedAsync(string sourceUrl)
        {
            if (string.IsNullOrEmpty(sourceUrl))
            {
                return null;
            }

            var response = await _httpClient.GetAsync(sourceUrl);
            if (!response.IsSuccessStatusCode)
            {
                return null;
            }

            var content = await response.Content.ReadAsStringAsync();
            var document = XDocument.Parse(content);
            var feed = new Feed
            {
                Title = document.Root.Element("title").Value,
                Description = document.Root.Element("description").Value,
                Entries = document.Root.Elements("entry").Select(ParseEntry).ToList()
            };

            return feed;
        }

        private Entry ParseEntry(XElement entry)
        {
            var id = entry.Element("id").Value;
            var title = entry.Element("title").Value;
            var content = entry.Element("content").Value;
            var published = DateTime.Parse(entry.Element("published").Value);
            var updated = DateTime.Parse(entry.Element("updated").Value);

            return new Entry
            {
                Id = id,
                Title = title,
                Content = content,
                Published = published,
                Updated = updated
            };
        }
    }
}

